// ─── EDITAR ESTAS DOS LÍNEAS ANTES DE ACTIVAR ───────────────
const SUPABASE_KEY = 'PEGAR_SERVICE_ROLE_KEY_AQUI';
const RESEND_KEY   = 'PEGAR_RESEND_API_KEY_AQUI';
// ─────────────────────────────────────────────────────────────

const SUPABASE_URL  = 'https://rflfsbrdmgaidhvbuvwb.supabase.co';
const FROM_EMAIL    = 'DidactIA IB <ib@didactia.eu>';
const SUPERADMIN_CC = 'jesvivlc@gmail.com';

const pad = n => String(n).padStart(2, '0');
const fmt = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
const now = new Date();
const today = fmt(now);
const fechaLegible = now.toLocaleDateString('es-ES', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

return [{ json: { SUPABASE_URL, SUPABASE_KEY, RESEND_KEY, FROM_EMAIL, SUPERADMIN_CC, today, fechaLegible } }];

const cfg = $('Config y fechas').first().json;

const _get = name => {
  const items = $(name).all();
  if (!items.length) return [];
  const first = items[0].json;
  if (Array.isArray(first)) return first;
  return items.map(i => i.json).filter(Boolean);
};

const ad = _get('Get Admins');
const pl = _get('Get Plazos');

// Escapado básico para datos de usuario en HTML
const esc = s => (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

// Agrupar plazos por centro_id
const plazosByCentro = {};
pl.forEach(p => {
  if (!plazosByCentro[p.centro_id]) plazosByCentro[p.centro_id] = [];
  plazosByCentro[p.centro_id].push(p);
});

// Calcular días restantes respecto a hoy
const todayDate = new Date(cfg.today + 'T12:00:00');
const daysDiff  = fechaStr => Math.ceil((new Date(fechaStr + 'T12:00:00') - todayDate) / 86400000);
const fmtFecha  = dateStr  => new Date(dateStr + 'T12:00:00').toLocaleDateString('es-ES', {
  day: 'numeric', month: 'short', year: 'numeric'
});

const TIPOS = {
  entrega_ia: 'Entrega IA', tok: 'TOK', cas: 'CAS',
  examen: 'Examen', formulario: 'Formulario', reunion: 'Reunión', otro: 'Otro'
};

// ── Estilos compartidos ──────────────────────────────────────
const TH  = `padding:8px 12px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.04em;color:#666;background:#f8f9fa;border-bottom:2px solid #e8e8e8;text-align:left;`;
const TD  = `padding:10px 12px;color:#333;font-size:13px;border-bottom:1px solid #f0f0f0;vertical-align:middle;`;
const TDC = `padding:10px 12px;color:#333;font-size:13px;border-bottom:1px solid #f0f0f0;text-align:center;vertical-align:middle;`;

const diasBadge = dias => {
  let color, label;
  if (dias < 0)        { color = '#b71c1c'; label = `Vencido +${Math.abs(dias)}d`; }
  else if (dias === 0) { color = '#c62828'; label = 'Hoy'; }
  else if (dias <= 2)  { color = '#c62828'; label = `${dias} día${dias === 1 ? '' : 's'}`; }
  else if (dias <= 7)  { color = '#e65100'; label = `${dias} días`; }
  else                 { color = '#1e6b3a'; label = `${dias} días`; }
  return `<span style='background:${color};color:#fff;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:700;white-space:nowrap;'>${label}</span>`;
};

const statCell = (count, color, label, isLast) =>
  `<td style='padding:18px 20px;text-align:center;${isLast ? '' : 'border-right:1px solid #e8e8e8;'}'>` +
  `<div style='font-size:32px;font-weight:700;color:${color};line-height:1;'>${count}</div>` +
  `<div style='font-size:10px;color:#888;margin-top:4px;text-transform:uppercase;'>${label}</div></td>`;

// ── Generar un email por coordinador (admin) ─────────────────
return ad.filter(a => a.email && String(a.email).includes('@')).flatMap(admin => {
  const cId  = admin.centro_id;
  const cNom = (admin.centros && admin.centros.nombre) || 'Centro';

  // Todos los plazos pendientes del centro con días calculados
  const myPlazos = (plazosByCentro[cId] || [])
    .map(p => ({ ...p, dias: daysDiff(p.fecha_limite) }))
    .sort((a, b) => a.dias - b.dias);

  // Solo enviar email si hay algún plazo en ≤7 días (o vencido)
  if (!myPlazos.some(p => p.dias <= 7)) return [];

  // Tabla: plazos ≤30 días y todos los vencidos
  const visible    = myPlazos.filter(p => p.dias <= 30);
  const hasOverdue = myPlazos.some(p => p.dias < 0);
  const hasUrgent  = myPlazos.some(p => p.dias >= 0 && p.dias <= 2);
  const isUrgente  = hasOverdue || hasUrgent;
  const alertCount = myPlazos.filter(p => p.dias <= 7).length;

  // Cabecera dinámica según urgencia
  const headerBg    = hasOverdue ? '#b71c1c' : isUrgente ? '#e65100' : '#1565c0';
  const headerLabel = hasOverdue
    ? 'Plazo IB vencido — Acción requerida'
    : isUrgente ? 'Plazo IB urgente próximo' : 'Plazos IB próximos';
  const subjPrefix  = hasOverdue ? '🚨 VENCIDO — ' : isUrgente ? '⚠️ URGENTE — ' : '';

  const rows = visible.map(p =>
    `<tr>` +
    `<td style='${TD}font-weight:600;'>${esc(p.titulo)}` +
    (p.descripcion ? `<div style='font-size:11px;color:#888;font-weight:400;margin-top:2px;'>${esc(p.descripcion)}</div>` : '') +
    `</td>` +
    `<td style='${TDC}white-space:nowrap;'>${fmtFecha(p.fecha_limite)}</td>` +
    `<td style='${TDC}'>${diasBadge(p.dias)}</td>` +
    `<td style='${TDC}'>${esc(TIPOS[p.tipo] || p.tipo || '—')}</td>` +
    `<td style='${TDC}'>${esc(p.afecta_a || '—')}</td>` +
    `</tr>`
  ).join('');

  const fallbackRow = `<tr><td colspan='5' style='${TD}text-align:center;color:#888;padding:16px;'>Sin plazos en los próximos 30 días</td></tr>`;

  const html =
    `<!DOCTYPE html><html lang='es'><head><meta charset='UTF-8'>` +
    `<meta name='viewport' content='width=device-width,initial-scale=1'>` +
    `<title>Plazos IB DidactIA</title></head>` +
    `<body style='margin:0;padding:0;background:#f4f4f5;font-family:-apple-system,BlinkMacSystemFont,sans-serif;'>` +
    `<div style='max-width:680px;margin:24px auto;background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 2px 16px rgba(0,0,0,0.09);'>` +
    `<div style='background:${headerBg};padding:28px 32px 24px;'>` +
    `<div style='font-size:11px;letter-spacing:0.1em;text-transform:uppercase;color:rgba(255,255,255,0.65);margin-bottom:6px;'>DidactIA — Programa IB · ${(visible[0] && visible[0].curso_escolar) || '2024-2025'}</div>` +
    `<div style='font-size:20px;font-weight:700;color:#fff;'>${headerLabel}</div>` +
    `<div style='font-size:13px;color:rgba(255,255,255,0.85);margin-top:5px;text-transform:capitalize;'>${cNom} · ${cfg.fechaLegible}</div>` +
    `</div>` +
    `<table width='100%' style='border-collapse:collapse;border-bottom:1px solid #e8e8e8;'><tr>` +
    statCell(myPlazos.filter(p => p.dias < 0).length,                 '#b71c1c', 'Vencidos',  false) +
    statCell(myPlazos.filter(p => p.dias >= 0 && p.dias <= 2).length, '#c62828', '0–2 días',  false) +
    statCell(myPlazos.filter(p => p.dias >= 3 && p.dias <= 7).length, '#e65100', '3–7 días',  false) +
    statCell(myPlazos.filter(p => p.dias > 7).length,                 '#1e6b3a', '> 7 días',  true) +
    `</tr></table>` +
    `<div style='padding:24px 32px 8px;'>` +
    `<div style='font-size:11px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase;color:#555;margin-bottom:12px;'>Plazos próximos y vencidos (≤ 30 días)</div>` +
    `<table width='100%' style='border-collapse:collapse;'>` +
    `<thead><tr>` +
    `<th style='${TH}'>Título / Descripción</th>` +
    `<th style='${TH}text-align:center;'>Fecha límite</th>` +
    `<th style='${TH}text-align:center;'>Tiempo</th>` +
    `<th style='${TH}text-align:center;'>Tipo</th>` +
    `<th style='${TH}text-align:center;'>Afecta a</th>` +
    `</tr></thead>` +
    `<tbody>${rows || fallbackRow}</tbody>` +
    `</table></div>` +
    `<div style='padding:14px 32px;border-top:1px solid #e8e8e8;background:#fafafa;'>` +
    `<div style='font-size:11px;color:#aaa;'>Generado por <strong style='color:#1a73e8;'>DidactIA</strong> — didactia.eu — No respondas a este email</div>` +
    `</div></div></body></html>`;

  return [{ json: {
    to:        String(admin.email).trim(),
    cc:        cfg.SUPERADMIN_CC,
    subject:   `${subjPrefix}DidactIA — Plazos IB: ${alertCount} en ≤7 días — ${cNom}`,
    html,
    fromEmail: cfg.FROM_EMAIL,
    resendKey: cfg.RESEND_KEY
  }}];
});
